import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';

function TeamLogWidget() {
  const [events, setEvents] = useState([]);
  const [expandedEvents, setExpandedEvents] = useState(new Set());
  const [isLoading, setIsLoading] = useState(true);
  const scrollContainerRef = React.useRef(null);
  const previousEventCountRef = useRef(0);
  const isInitialLoadRef = useRef(true);

  // Standup state (read-only for concluded standups)
  const [standups, setStandups] = useGlobalStorage('team-standups', []);
  const [expandedStandups, setExpandedStandups] = useState(new Set());

  // AI state for search functionality
  const [pepperThinkingState, setPepperThinkingState] = useGlobalStorage('pepper-thinking', null);
  const [userName] = useGlobalStorage('user-name', 'User');

  // Filter state (both checked by default)
  const [showEvents, setShowEvents] = useState(true);
  const [showStandups, setShowStandups] = useState(true);

  // Search state
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResponse, setSearchResponse] = useState('');
  const [isSearching, setIsSearching] = useState(false);

  // Citation navigation state
  const [activeCitations, setActiveCitations] = useState([]);
  const [currentCitationIndex, setCurrentCitationIndex] = useState(0);
  const [highlightedEventIds, setHighlightedEventIds] = useState(new Set());

  // Auto-scroll to bottom when events change - using instant scroll for smoother experience
  const scrollToBottom = useCallback((instant = false) => {
    if (scrollContainerRef.current) {
      if (instant) {
        scrollContainerRef.current.scrollTop = scrollContainerRef.current.scrollHeight;
      } else {
        scrollContainerRef.current.scrollTo({
          top: scrollContainerRef.current.scrollHeight,
          behavior: 'smooth'
        });
      }
    }
  }, []);

  // Load events on mount and listen for updates
  useEffect(() => {
    loadEvents();

    // Listen for global storage changes to update in real-time
    const handleStorageChange = (event) => {
      if (event.data.type === 'canvas-storage-sync' && 
          event.data.scope === 'global' && 
          event.data.storage && 
          event.data.storage['team-log-widget-events']) {
        const newEvents = JSON.parse(event.data.storage['team-log-widget-events']);

        // Only scroll if we're getting new events (not initial load)
        if (!isInitialLoadRef.current && newEvents.length > previousEventCountRef.current) {
          setEvents(newEvents);
          // Use requestAnimationFrame to ensure the DOM has updated before scrolling
          requestAnimationFrame(() => {
            requestAnimationFrame(() => {
              scrollToBottom(false);
            });
          });
        } else {
          setEvents(newEvents);
        }

        previousEventCountRef.current = newEvents.length;
      }
    };

    window.addEventListener('message', handleStorageChange);
    return () => window.removeEventListener('message', handleStorageChange);
  }, [scrollToBottom]);

  // Scroll to bottom after initial load only
  useEffect(() => {
    if (!isLoading && events.length > 0 && isInitialLoadRef.current) {
      isInitialLoadRef.current = false;
      previousEventCountRef.current = events.length;
      // Instant scroll on initial load
      requestAnimationFrame(() => {
        scrollToBottom(true);
      });
    }
  }, [isLoading, events.length, scrollToBottom]);

  const loadEvents = async () => {
    try {
      setIsLoading(true);
      const logEvents = await miyagiWidgetLog.getEvents();
      setEvents(logEvents);
    } catch (error) {
      console.error('Failed to load events:', error);
    } finally {
      setIsLoading(false);
    }
  };

  // Filter to only show concluded standups (those with concludedAt)
  const concludedStandups = standups.filter(standup => standup.concludedAt);

  // Toggle standup collapse/expand (read-only)
  const toggleStandupCollapse = (standupId) => {
    const newExpanded = new Set(expandedStandups);
    if (newExpanded.has(standupId)) {
      newExpanded.delete(standupId);
    } else {
      newExpanded.add(standupId);
    }
    setExpandedStandups(newExpanded);
  };

  // Format widget events for AI search context
  const formatWidgetEventsForAI = (events) => {
    if (!events || events.length === 0) {
      return "No widget events available.";
    }

    const eventsByType = events.reduce((acc, event) => {
      if (!acc[event.type]) acc[event.type] = [];
      acc[event.type].push(event);
      return acc;
    }, {});

    let result = `WIDGET EVENTS (${events.length} total):`;

    Object.entries(eventsByType).forEach(([type, typeEvents]) => {
      result += `\n\n${type.toUpperCase()} EVENTS (${typeEvents.length}):`;
      typeEvents.forEach(event => {
        const date = new Date(event.timestamp).toLocaleDateString();
        const time = new Date(event.timestamp).toLocaleTimeString();
        result += `\n- [ID: ${event.id}] ${event.summary} (${date} at ${time})`;
        if (event.details) {
          result += `\n  Details: ${event.details}`;
        }
      });
    });

    return result;
  };

  // Format standup summaries for AI search context
  const formatStandupSummariesForAI = (standups) => {
    if (!standups || standups.length === 0) {
      return "No standup summaries available.";
    }

    const concludedStandups = standups.filter(s => s.concludedAt);

    if (concludedStandups.length === 0) {
      return "No concluded standup summaries available.";
    }

    let result = `STANDUP SUMMARIES (${concludedStandups.length} concluded):`;

    concludedStandups.forEach(standup => {
      const date = new Date(standup.concludedAt).toLocaleDateString();
      const time = new Date(standup.concludedAt).toLocaleTimeString();
      result += `\n\n- [ID: ${standup.id}] "${standup.title}" (concluded ${date} at ${time})`;
      if (standup.summary) {
        result += `\n  Summary: ${standup.summary}`;
      }
      if (standup.messages && standup.messages.length > 0) {
        result += `\n  Key Discussion Points:`;
        standup.messages.slice(-5).forEach(msg => {
          result += `\n    ${msg.author}: ${msg.text}`;
        });
      }
    });

    return result;
  };

  // Parse AI response for event citations and extract referenced events
  const parseEventCitations = (responseText) => {
    const citations = [];

    // Find EVENT citations: [EVENT:event_id] or [EVENT:numeric_id]
    const eventMatches = responseText.match(/\[EVENT:([^\]]+)\]/g);
    if (eventMatches) {
      eventMatches.forEach(match => {
        const citedId = match.match(/\[EVENT:([^\]]+)\]/)[1];

        // Try exact match first
        let event = events.find(e => e.id === citedId);

        // If no exact match, try to find by numeric portion (timestamp)
        if (!event) {
          // Extract numeric part if it exists
          const numericMatch = citedId.match(/(\d+)/);
          if (numericMatch) {
            const numericId = numericMatch[1];
            event = events.find(e => e.id.includes(numericId));
          }
        }

        if (event) {
          citations.push({
            type: 'event',
            id: event.id, // Use the actual full ID
            data: event
          });
        } else {
          console.log('🔍 Could not find event for citation:', citedId);
        }
      });
    }

    // Find STANDUP citations: [STANDUP:standup_id]
    const standupMatches = responseText.match(/\[STANDUP:([^\]]+)\]/g);
    if (standupMatches) {
      standupMatches.forEach(match => {
        const citedId = match.match(/\[STANDUP:([^\]]+)\]/)[1];

        // Try exact match in standups array first
        let standup = standups.find(s => s.id === citedId);

        // If no exact match, try to find by numeric portion (timestamp) 
        if (!standup) {
          const numericMatch = citedId.match(/(\d+)/);
          if (numericMatch) {
            const numericId = numericMatch[1];

            // Try finding in standups array by numeric portion
            standup = standups.find(s => s.id && s.id.includes(numericId));

            // If still not found, try finding standup-related event in events array
            if (!standup) {
              const standupEvent = events.find(e => 
                (e.type === 'standup-created' || e.type === 'standup-concluded') && 
                (e.id.includes(numericId) || 
                 (e.details && e.details.standupId && e.details.standupId.includes(numericId)))
              );

              if (standupEvent) {
                // Use the event as a standup reference
                standup = standupEvent;
              }
            }
          }
        }

        if (standup) {
          citations.push({
            type: 'standup',
            id: standup.id,
            data: standup
          });
        } else {
          console.log('🔍 Could not find standup for citation:', citedId);
        }
      });
    }

    return citations;
  };

  // Format citations for display
  const formatCitationsForDisplay = (citations) => {
    if (citations.length === 0) {
      return '';
    }

    let result = '\n\n--- Referenced Events ---\n';

    citations.forEach((citation, index) => {
      if (citation.type === 'event') {
        const event = citation.data;
        const date = new Date(event.timestamp).toLocaleDateString();
        const time = new Date(event.timestamp).toLocaleTimeString();
        result += `\n${index + 1}. ${event.type.toUpperCase()}: ${event.summary}`;
        result += `\n   ${date} at ${time}`;
        if (event.details) {
          result += `\n   Details: ${event.details}`;
        }
      } else if (citation.type === 'standup') {
        const standup = citation.data;

        // Handle both standup objects and standup events
        if (standup.type === 'standup-created' || standup.type === 'standup-concluded') {
          // This is a standup event from the events array
          const date = new Date(standup.timestamp).toLocaleDateString();
          const time = new Date(standup.timestamp).toLocaleTimeString();
          result += `\n${index + 1}. ${standup.type.toUpperCase()}: ${standup.summary}`;
          result += `\n   ${date} at ${time}`;
          if (standup.details) {
            result += `\n   Details: ${JSON.stringify(standup.details)}`;
          }
        } else {
          // This is an actual standup object
          const date = standup.concludedAt ? new Date(standup.concludedAt).toLocaleDateString() : 'Not concluded';
          const time = standup.concludedAt ? new Date(standup.concludedAt).toLocaleTimeString() : '';
          result += `\n${index + 1}. STANDUP: "${standup.title || 'Untitled Standup'}"`;
          result += `\n   ${standup.concludedAt ? `Concluded ${date} at ${time}` : 'In progress'}`;
          if (standup.summary) {
            result += `\n   Summary: ${standup.summary}`;
          }
        }
      }
      result += '\n';
    });

    return result;
  };

  // Citation navigation functions
  const highlightCitation = (citationIndex) => {
    if (!activeCitations || activeCitations.length === 0) {
      console.log('🔍 No active citations to highlight');
      return;
    }

    const citation = activeCitations[citationIndex];
    if (!citation) {
      console.log('🔍 No citation at index:', citationIndex);
      return;
    }

    const eventId = citation.id;
    console.log('🔍 Highlighting citation', citationIndex + 1, 'of', activeCitations.length, '- Event ID:', eventId);

    // Scroll to event in timeline
    const eventElement = document.getElementById(`timeline-item-${eventId}`);
    if (eventElement) {
      console.log('🔍 Found timeline element, scrolling to:', eventId);
      eventElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
    } else {
      console.log('🔍 Could not find timeline element for:', eventId);
      // Try again after a short delay in case the element is still rendering
      setTimeout(() => {
        const retryElement = document.getElementById(`timeline-item-${eventId}`);
        if (retryElement) {
          console.log('🔍 Found timeline element on retry, scrolling to:', eventId);
          retryElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else {
          console.log('🔍 Timeline element still not found after retry:', eventId);
        }
      }, 200);
    }
  };

  const navigateToCitation = (index) => {
    if (index >= 0 && index < activeCitations.length) {
      setCurrentCitationIndex(index);

      // Update highlight to only show current citation (useEffect will handle scrolling)
      const currentCitationId = activeCitations[index].id;
      setHighlightedEventIds(new Set([currentCitationId]));
    }
  };

  const nextCitation = () => {
    if (currentCitationIndex < activeCitations.length - 1) {
      navigateToCitation(currentCitationIndex + 1);
    }
  };

  const previousCitation = () => {
    if (currentCitationIndex > 0) {
      navigateToCitation(currentCitationIndex - 1);
    }
  };

  const clearSearch = () => {
    setSearchQuery('');
    setSearchResponse('');
    setActiveCitations([]);
    setCurrentCitationIndex(0);
    setHighlightedEventIds(new Set());
    scrollToBottom(); // Scroll log to bottom
  };

  // Auto-scroll when highlighted items change
  useEffect(() => {
    if (highlightedEventIds.size > 0 && activeCitations.length > 0) {
      const highlightedId = Array.from(highlightedEventIds)[0];
      console.log('🔍 useEffect triggered - scrolling to highlighted item:', highlightedId);

      // Wait for DOM to update, then scroll
      const scrollTimeout = setTimeout(() => {
        const element = document.getElementById(`timeline-item-${highlightedId}`);
        if (element) {
          console.log('🔍 Found element in useEffect, scrolling');
          element.scrollIntoView({ behavior: 'smooth', block: 'center' });
        } else {
          console.log('🔍 Element not found in useEffect:', highlightedId);

          // Try one more time after a longer delay
          setTimeout(() => {
            const retryElement = document.getElementById(`timeline-item-${highlightedId}`);
            if (retryElement) {
              console.log('🔍 Found element on retry in useEffect, scrolling');
              retryElement.scrollIntoView({ behavior: 'smooth', block: 'center' });
            } else {
              console.log('🔍 Element still not found after retry in useEffect');
            }
          }, 500);
        }
      }, 100);

      return () => clearTimeout(scrollTimeout);
    }
  }, [highlightedEventIds, activeCitations]);

  // Handle search queries
  const handleSearch = async (query) => {
    if (!query.trim()) return;

    setIsSearching(true);
    setSearchResponse(''); // Clear previous response
    setActiveCitations([]); // Clear previous citations
    setHighlightedEventIds(new Set()); // Clear previous highlights

    try {
      // Enhanced system prompt for search functionality
      const systemPrompt = `You are Pepper, an AI assistant helping users search and analyze their team activity log.

SEARCH CONTEXT:
- User Query: "${query.trim()}"
- User: ${userName}

AVAILABLE DATA:
${formatWidgetEventsForAI(events)}

${formatStandupSummariesForAI(standups)}

SEARCH INSTRUCTIONS:
- Provide direct, factual answers to the user's query
- Reference specific dates, times, and event details when relevant
- If no relevant information is found, say so clearly
- Keep responses concise but informative
- Focus on answering the specific question asked
- When mentioning events, include the date/time context
- Be helpful and professional in tone

CITATION FORMAT:
When referencing specific events in your response, include the event ID in brackets like this:
- For widget events: "The task was created [EVENT:event_id_here] on Sept 25th"
- For standup events: "In the standup discussion [STANDUP:standup_id_here] team members mentioned..."

IMPORTANT: Use the ID shown in the data above. You can use either the full ID or just the numeric portion (timestamp). For example, for an event with ID "event-1759181422993-pa2kywdmg", you can reference it as either [EVENT:event-1759181422993-pa2kywdmg] or [EVENT:1759181422993].`;

      console.log('🔍 Making search API call');
      console.log('🔍 Standups data:', standups);
      console.log('🔍 Concluded standups:', standups.filter(s => s.concludedAt));

      // Real API call to LLM using authenticated miyagiAPI() function
      const data = await miyagiAPI('generate-text', {
        prompt: query.trim(),
        system_prompt: systemPrompt,
        max_tokens: 300,
        temperature: 0.3  // Lower temperature for more factual responses
      });

      console.log('🔍 Search response received:', data);

      const responseText = data || 'Sorry, I had trouble searching. Please try again.';

      // Parse citations
      const citations = parseEventCitations(responseText);

      // Clean response by removing citation markers
      const cleanResponse = responseText
        .replace(/\[EVENT:[^\]]+\]/g, '')
        .replace(/\[STANDUP:[^\]]+\]/g, '')
        .replace(/\s+/g, ' ')  // Clean up extra spaces
        .trim();

      // Debug logging
      console.log('🔍 Raw AI Response:', responseText);
      console.log('🔍 Parsed Citations:', citations);
      console.log('🔍 Clean Response:', cleanResponse);

      // Set response and citations
      setSearchResponse(cleanResponse);
      setActiveCitations(citations);

      // Set citations and highlight first one
      if (citations.length > 0) {
        setCurrentCitationIndex(0);

        // Highlight first citation
        const firstCitationId = citations[0].id;
        setHighlightedEventIds(new Set([firstCitationId]));

        console.log('🔍 Set to highlight first citation:', firstCitationId);
      } else {
        setHighlightedEventIds(new Set());
        setCurrentCitationIndex(0);
      }

    } catch (error) {
      console.error('🔍 Search failed:', error);
      setSearchResponse('Sorry, search failed. Please try again.');
    } finally {
      setIsSearching(false);
    }
  };

  // Create combined timeline of events and concluded standups
  const combinedTimeline = useMemo(() => {
    const items = [];

    // Add events
    if (showEvents) {
      events.forEach(event => {
        items.push({
          type: 'event',
          timestamp: event.timestamp,
          data: event
        });
      });
    }

    // Add concluded standups (use concludedAt as timestamp for chronological ordering)
    if (showStandups) {
      concludedStandups.forEach(standup => {
        items.push({
          type: 'standup',
          timestamp: standup.concludedAt,
          data: standup
        });
      });
    }

    // Sort all items by timestamp
    items.sort((a, b) => a.timestamp - b.timestamp);

    // Group by day
    const grouped = {};
    items.forEach(item => {
      const date = new Date(item.timestamp);
      const dayKey = date.toDateString();

      if (!grouped[dayKey]) {
        grouped[dayKey] = [];
      }
      grouped[dayKey].push(item);
    });

    // Sort days in ascending order (oldest first, newest at bottom)
    const sortedDays = Object.keys(grouped).sort((a, b) => {
      return new Date(a) - new Date(b);
    });

    return { grouped, sortedDays };
  }, [events, concludedStandups, showEvents, showStandups]);

  const toggleEventDetails = (eventId) => {
    const newExpanded = new Set(expandedEvents);
    if (newExpanded.has(eventId)) {
      newExpanded.delete(eventId);
    } else {
      newExpanded.add(eventId);
    }
    setExpandedEvents(newExpanded);
  };

  const formatTime = (timestamp) => {
    return new Date(timestamp).toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      hour12: true
    });
  };

  const formatDay = (dateString) => {
    const date = new Date(dateString);
    const today = new Date();
    const yesterday = new Date();
    yesterday.setDate(today.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return 'Today';
    } else if (date.toDateString() === yesterday.toDateString()) {
      return 'Yesterday';
    } else {
      return date.toLocaleDateString('en-US', {
        weekday: 'long',
        month: 'long',
        day: 'numeric'
      });
    }
  };

  const getEventIcon = (type) => {
    switch (type) {
      case 'task-created': return '✅';
      case 'task-deleted': return '✕';
      case 'task-status-changed': return '○';
      case 'task-updated': return '✏️';
      case 'task-due-date-changed': return '📅';
      case 'group-name-changed': return '✏️';
      case 'group-deleted': return '✕';
      case 'group-created': return '📁';
      case 'standup-created': return '�';
      default: return '•';
    }
  };

  const getEventColor = (type) => {
    switch (type) {
      case 'task-created': return '#4CAF50';
      case 'task-deleted': return '#f44336';
      case 'task-status-changed': return '#2196F3';
      case 'task-updated': return '#FF9800';
      case 'task-due-date-changed': return '#9C27B0';
      case 'group-name-changed': return '#607D8B';
      case 'group-deleted': return '#795548';
      case 'group-created': return '#4CAF50';
      case 'standup-created': return '#2196F3';
      default: return '#666';
    }
  };

  // Generate consistent color for user names based on their name
  const getUserColor = (userName) => {
    const colors = [
      '#e74c3c', '#3498db', '#2ecc71', '#f39c12', '#9b59b6',
      '#1abc9c', '#34495e', '#e67e22', '#95a5a6', '#f1c40f',
      '#8e44ad', '#2980b9', '#27ae60', '#d35400', '#7f8c8d'
    ];

    // Simple hash function to get consistent color for same name
    let hash = 0;
    for (let i = 0; i < userName.length; i++) {
      hash = userName.charCodeAt(i) + ((hash << 5) - hash);
    }

    return colors[Math.abs(hash) % colors.length];
  };

  // Format user name with colored badge
  const formatUserTag = (userName) => {
    const color = getUserColor(userName);
    return (
      <span key={userName} style={{
        display: 'inline-flex',
        alignItems: 'center',
        gap: '4px',
        background: color,
        color: 'white',
        padding: '2px 8px',
        borderRadius: '12px',
        fontSize: '11px',
        fontWeight: '600',
        margin: '0 2px'
      }}>
        <span style={{
          width: '12px',
          height: '12px',
          borderRadius: '50%',
          background: 'rgba(255, 255, 255, 0.3)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: '8px',
          fontWeight: '700'
        }}>
          {userName.charAt(0).toUpperCase()}
        </span>
        {userName}
      </span>
    );
  };

  // Parse event summary to detect and format user names based on event details
  const parseEventSummary = (summary, eventDetails) => {
    // Only format user names if we have explicit user information in the event details
    const knownUserNames = new Set();

    // Extract known user names from event details
    if (eventDetails) {
      // Check for various user fields in the event details
      if (eventDetails.createdBy) knownUserNames.add(eventDetails.createdBy);
      if (eventDetails.updatedBy) knownUserNames.add(eventDetails.updatedBy);
      if (eventDetails.deletedBy) knownUserNames.add(eventDetails.deletedBy);
      if (eventDetails.changedBy) knownUserNames.add(eventDetails.changedBy);
    }

    // If no known user names, return original summary
    if (knownUserNames.size === 0) {
      return summary;
    }

    // Replace only the known user names with formatted tags
    const parts = [];
    let remainingText = summary;

    knownUserNames.forEach(userName => {
      if (!userName || userName === 'Unknown User') return;

      // Find the first occurrence of this specific user name
      const userIndex = remainingText.indexOf(userName);
      if (userIndex !== -1) {
        // Add text before the user name
        if (userIndex > 0) {
          parts.push(remainingText.substring(0, userIndex));
        }

        // Add the formatted user tag
        parts.push(formatUserTag(userName));

        // Update remaining text to continue after this user name
        remainingText = remainingText.substring(userIndex + userName.length);
      }
    });

    // Add any remaining text
    if (remainingText) {
      parts.push(remainingText);
    }

    // Return parts array if we made replacements, otherwise original summary
    return parts.length > 1 ? parts : summary;
  };

  const clearDayEvents = async (dayKey) => {
    if (confirm(`Are you sure you want to clear all events and standups for ${formatDay(dayKey)}? This cannot be undone.`)) {
      try {
        // Filter out events for this specific day
        const eventsToKeep = events.filter(event => {
          const eventDay = new Date(event.timestamp).toDateString();
          return eventDay !== dayKey;
        });

        // Filter out standups for this specific day
        const standupsToKeep = standups.filter(standup => {
          const standupDay = new Date(standup.createdAt).toDateString();
          return standupDay !== dayKey;
        });

        // Update global storage for events
        parent.postMessage({
          type: 'canvas-storage-update',
          scope: 'global',
          key: 'team-log-widget-events',
          value: JSON.stringify(eventsToKeep)
        }, '*');

        // Update standups storage
        setStandups(standupsToKeep);

        setEvents(eventsToKeep);

        // Clear any expanded events for this day
        const newExpanded = new Set(expandedEvents);
        eventsByDay.grouped[dayKey]?.forEach(event => {
          newExpanded.delete(event.id);
        });
        setExpandedEvents(newExpanded);

        // Clear any expanded standups for this day
        const newExpandedStandups = new Set(expandedStandups);
        // Clear any summaries for this day
        const newSummaries = { ...standupSummaries };

        standups.forEach(standup => {
          const standupDay = new Date(standup.createdAt).toDateString();
          if (standupDay === dayKey) {
            newExpandedStandups.delete(standup.id);
            // Remove summary for this standup
            delete newSummaries[standup.id];
            // If we're clearing the active standup, deactivate it and clear AI state
            if (activeStandupId === standup.id) {
              setActiveStandupId(null);
              setPepperThinkingState(null);
            }
          }
        });
        setExpandedStandups(newExpandedStandups);
        setStandupSummaries(newSummaries);

      } catch (error) {
        console.error('Failed to clear day events and standups:', error);
      }
    }
  };

  if (isLoading) {
    return (
      <div style={{
