        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '12px',
        paddingBottom: '8px',
        borderBottom: '1px solid rgba(0, 0, 0, 0.1)'
      }}>
        <span style={{ fontWeight: '600', fontSize: '13px' }}>Comments</span>
        <button
          onClick={() => onToggleComments(taskId)}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            fontSize: '16px',
            color: '#999',
            padding: '0',
            lineHeight: '1'
          }}
        >
          ✕
        </button>
      </div>

      {/* Comments List */}
      <div style={{ marginBottom: '12px' }}>
        {comments.length === 0 ? (
          <div style={{
            padding: '12px',
            textAlign: 'center',
            color: '#999',
            fontSize: '12px',
            fontStyle: 'italic'
          }}>
            No comments yet
          </div>
        ) : (
          comments.map(comment => (
            <Comment
              key={comment.id}
              comment={comment}
              currentUser={currentUser}
              isEditing={editingCommentId === comment.id}
              editText={editCommentText}
              onEditTextChange={setEditCommentText}
              onSave={() => onUpdateComment(comment.id)}
              onCancelEdit={() => {
                setEditCommentText('');
                onStartEditComment(null);
              }}
              onStartEdit={() => onStartEditComment(comment)}
              onDelete={() => onDeleteComment(comment.id)}
            />
          ))
        )}
      </div>

      {/* Add Comment Form */}
      <CommentForm
        value={newCommentText}
        onChange={setNewCommentText}
        onSubmit={() => onAddComment(taskId)}
      />
    </div>
  );
}
